INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-a5729396-moex-00104', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-1611a566', 'sub-aboriginal-a5729396-03', NULL, 'single_choice', '甲為支付工程款開支票給乙，發票地為臺北市、付款地為臺中市，因乙工程施作品質不佳，甲拒絕支 付票款。關於管轄法院，下列敘述何者錯誤？', '["甲如為法人，設主營業所在嘉義，乙得向臺灣嘉義地院提起訴訟", "甲如為法人，設主事務所在臺北，乙得向臺灣臺北地院提起訴訟", "乙得向支票付款地臺灣臺中地方法院提起訴訟", "乙得向支票發票地臺灣臺北地方法院提起訴訟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00105', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-1611a566', 'sub-aboriginal-a5729396-03', NULL, 'single_choice', '甲將其所有套房分別出租給乙、丙，因乙、丙均遲交租金，甲遂以乙、丙為共同被告，起訴請求給付 租金。下列敘述何者正確？', '["甲如果同意撤回對乙之訴訟，其撤回之效力及於丙", "法院如果認定乙欠缺訴訟能力，應命甲補正，若甲不予補正，應裁定駁回全部訴訟", "法院最終判決甲勝訴，乙決定捨棄上訴，乙捨棄上訴之效力不及於丙", "訴訟程序中，如乙、丙中1人死亡，訴訟發生當然全部停止之效力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00106', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-1611a566', 'sub-aboriginal-a5729396-03', NULL, 'single_choice', '原告甲主張其為買受人，列出賣人乙為被告，主張已全額支付買賣價金，惟乙卻未交付買賣標的物A 屋，乃起訴請求乙返還已付之價金新臺幣（下同）1,000萬元、違約金200萬元及因不履行買賣契約 所生之損害賠償300萬元，共計1,500萬元整。就本件訴訟標的價額之核定，下列敘述何者正確？', '["以請求返還價金部分之1,000萬元定之", "以請求之全部金額共1,500萬元定之", "以請求違約金之部分與返還價金之部分合計共1,200萬元定之", "以請求損害賠償之部分與返還價金之部分合計共1,300萬元定之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00107', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-1611a566', 'sub-aboriginal-a5729396-03', NULL, 'single_choice', '甲前往某大學法律扶助社尋求協助，表示其前因感染新冠肺炎入院隔離治療，且大樓管理員未即時轉 交民事第一審判決書，致未能及時上訴。則關於該法律扶助社對甲為聲請回復原狀之建議，下列敘述 何者錯誤？', '["甲聲請回復原狀之事由，必須是通常人之注意不能預見而有不能委任代理或不能以其他方法避免遲 誤之情形，方足當之", "甲如果僅以管理員未將該判決書正本及時轉交，造成甲遲誤上訴期間，不能認為是得聲請回復原狀 之事由", "甲入院隔離治療時，如果是發生在上訴之不變期間屆滿後，不能據以聲請回復原狀", "甲應先聲請回復原狀，待法院准許回復原狀之聲請後，甲始得再補行上訴"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00108', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-1611a566', 'sub-aboriginal-a5729396-03', NULL, 'single_choice', '關於訴訟程序之停止，下列敘述何者正確？', '["對於停止訴訟程序之裁定，不得抗告", "對於停止訴訟程序之裁定，法院僅得依當事人之聲請撤銷之", "對於撤銷停止訴訟程序之裁定，得為抗告", "訴訟程序停止期間，法院得視事件狀況，依職權定暫時狀態之處分"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00109', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-1611a566', 'sub-aboriginal-a5729396-03', NULL, 'single_choice', '關於判決，下列敘述何者錯誤？', '["宣示判決，必須當事人在場，方有效力", "法官非參與為判決基礎之辯論者，不得參與判決", "法院為判決時，依自由心證判斷事實之真偽", "判決原則上應本於當事人之言詞辯論為之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00110', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-1611a566', 'sub-aboriginal-a5729396-03', NULL, 'single_choice', '下列何種情形，法院不應以原告起訴不合法而駁回之？', '["原告主張之訴訟標的，已經為前訴訟之確定判決效力所及", "非專屬管轄之事件，受訴法院認為自己並無管轄權，惟被告未就此提出抗辯且已為本案之辯論", "原告欠缺當事人能力", "起訴係基於惡意，且事實上或法律上之主張欠缺合理依據"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00111', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-1611a566', 'sub-aboriginal-a5729396-03', NULL, 'single_choice', '關於訴之客觀預備合併，下列敘述何者錯誤？', '["原告先位請求勝訴，備位請求既然未受裁判，故之後被告合法上訴時，該備位請求並不發生移審 效力", "對於互斥之兩請求，得提起客觀預備合併之訴", "法院如認為先位之訴有理由時，即無庸就備位請求為調查裁判", "係指原告將各請求排列成為先、備位，要求法院先審理先位請求，於認為該請求不合法或無理由時， 始審理備位請求之合併型態"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00112', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-1611a566', 'sub-aboriginal-a5729396-03', NULL, 'single_choice', '下列何者，原告不得撤回起訴？', '["起訴狀送達被告後", "法院之判決確定後", "法院已為終局判決後", "被告已為本案言詞辯論後"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00113', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-1611a566', 'sub-aboriginal-a5729396-03', NULL, 'single_choice', '下列何者不屬於強制調解事件？', '["因請求保護占有涉訟者", "因增加或減免不動產之租金發生爭執者", "因定不動產之界線或設置界標發生爭執者", "因道路交通事故發生爭執者"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL)
